class MainActivity : AppCompatActivity() {

    private lateinit var webView: WebView
    private lateinit var nativeBridge: NativeBridge

    private lateinit var cameraPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var notificationPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var takePictureLauncher: ActivityResultLauncher<Void?>
    private lateinit var fileChooserLauncher: ActivityResultLauncher<Array<String>>

    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null
    private var pendingCameraCallback: String? = null

    companion object {
        private const val TAG = "WebViewWrapper"
        private const val WEB_APP_URL = "file:///android_asset/index.html" // Change to your web app URL
        private const val NOTIFICATION_CHANNEL_ID = "web_app_notifications"
        private const val NOTIFICATION_CHANNEL_NAME = "Web App Notifications"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        setupActivityResultLaunchers()
        createNotificationChannel()
        setupWebView()

        setContentView(webView)
        webView.loadUrl(WEB_APP_URL)
    }

    private fun setupActivityResultLaunchers() {
        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            val callback = pendingCameraCallback
            if (isGranted && callback != null) {
                launchCamera(callback)
            } else {
                webView.evaluateJavascript(
                    "javascript:window.NativeBridgeCallbacks && window.NativeBridgeCallbacks['$pendingCameraCallback'] && window.NativeBridgeCallbacks['$pendingCameraCallback']({error: 'Camera permission denied'})",
                    null
                )
                pendingCameraCallback = null
            }
        }

        notificationPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            if (isGranted) {
                webView.evaluateJavascript(
                    "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult(true)",
                    null
                )
            } else {
                webView.evaluateJavascript(
                    "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult(false)",
                    null
                )
            }
        }

        takePictureLauncher = registerForActivityResult(
            ActivityResultContracts.TakePicturePreview()
        ) { bitmap ->
            val callback = pendingCameraCallback
            if (bitmap != null && callback != null) {
                val base64 = bitmapToBase64(bitmap)
                webView.evaluateJavascript(
                    "javascript:window.NativeBridgeCallbacks && window.NativeBridgeCallbacks['$callback'] && window.NativeBridgeCallbacks['$callback']({success: true, data: '$base64'})",
                    null
                )
            } else {
                webView.evaluateJavascript(
                    "javascript:window.NativeBridgeCallbacks && window.NativeBridgeCallbacks['$callback'] && window.NativeBridgeCallbacks['$callback']({error: 'Camera capture cancelled'})",
                    null
                )
            }
            pendingCameraCallback = null
        }

        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.OpenDocument()
        ) { uri ->
            if (uri != null) {
                fileUploadCallback?.onReceiveValue(arrayOf(uri))
            } else {
                fileUploadCallback?.onReceiveValue(null)
            }
            fileUploadCallback = null
        }
    }

    private fun setupWebView() {
        webView = WebView(this).apply {
            settings.apply {
                javaScriptEnabled = true
                domStorageEnabled = true
                databaseEnabled = true
                allowFileAccess = true
                allowContentAccess = true
                mediaPlaybackRequiresUserGesture = false
                mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
                cacheMode = WebSettings.LOAD_DEFAULT
                setSupportZoom(true)
                builtInZoomControls = true
                displayZoomControls = false
                useWideViewPort = true
                loadWithOverviewMode = true

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                    safeBrowsingEnabled = true
                }

                userAgentString = "$userAgentString WebViewWrapper/1.0"
            }

            nativeBridge = NativeBridge(this@MainActivity, this)
            addJavascriptInterface(nativeBridge, "NativeBridge")

            webViewClient = AppWebViewClient()
            webChromeClient = AppWebChromeClient()
        }
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                NOTIFICATION_CHANNEL_NAME,
                NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Notifications from the web app"
            }
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    fun requestCameraPermissionAndLaunch(callbackId: String) {
        pendingCameraCallback = callbackId
        when {
            ContextCompat.checkSelfPermission(this, Manifest.permission.CAMERA) ==
                    PackageManager.PERMISSION_GRANTED -> {
                launchCamera(callbackId)
            }
            else -> {
                cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
            }
        }
    }

    private fun launchCamera(callbackId: String) {
        pendingCameraCallback = callbackId
        takePictureLauncher.launch(null)
    }

    fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            when {
                ContextCompat.checkSelfPermission(
                    this, Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED -> {
                    webView.evaluateJavascript(
                        "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult(true)",
                        null
                    )
                }
                else -> {
                    notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                }
            }
        } else {
            webView.evaluateJavascript(
                "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult(true)",
                null
            )
        }
    }

    fun showNotification(title: String, body: String, notificationId: Int) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU &&
            ContextCompat.checkSelfPermission(this, Manifest.permission.POST_NOTIFICATIONS) !=
            PackageManager.PERMISSION_GRANTED
        ) {
            Log.w(TAG, "Notification permission not granted")
            return
        }

        val builder = NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentTitle(title)
            .setContentText(body)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setAutoCancel(true)

        NotificationManagerCompat.from(this).notify(notificationId, builder.build())
    }

    private fun bitmapToBase64(bitmap: Bitmap): String {
        val outputStream = ByteArrayOutputStream()
        bitmap.compress(Bitmap.CompressFormat.JPEG, 85, outputStream)
        val byteArray = outputStream.toByteArray()
        return Base64.encodeToString(byteArray, Base64.NO_WRAP)
    }

    inner class AppWebViewClient : WebViewClient() {
        override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
            super.onPageStarted(view, url, favicon)
            Log.d(TAG, "Page started loading: $url")
        }

        override fun onPageFinished(view: WebView?, url: String?) {
            super.onPageFinished(view, url)
            Log.d(TAG, "Page finished loading: $url")
            injectBridgeHelpers(view)
        }

        override fun onReceivedError(
            view: WebView?,
            request: WebResourceRequest?,
            error: WebResourceError?
        ) {
            super.onReceivedError(view, request, error)
            Log.e(TAG, "WebView error: ${error?.description}")
        }

        private fun injectBridgeHelpers(view: WebView?) {
            val jsCode = """
                (function() {
                    if (window.NativeBridgeReady) return;
                    
                    window.NativeBridgeCallbacks = {};
                    var callbackCounter = 0;
                    
                    window.NativeAPI = {
                        takePhoto: function() {
                            return new Promise(function(resolve, reject) {
                                var callbackId = 'camera_' + (++callbackCounter);
                                window.NativeBridgeCallbacks[callbackId] = function(result) {
                                    delete window.NativeBridgeCallbacks[callbackId];
                                    if (result.error) {
                                        reject(new Error(result.error));
                                    } else {
                                        resolve(result.data);
                                    }
                                };
                                NativeBridge.openCamera(callbackId);
                            });
                        },
                        
                        setItem: function(key, value) {
                            NativeBridge.setStorageItem(key, typeof value === 'string' ? value : JSON.stringify(value));
                        },
                        
                        getItem: function(key) {
                            var result = NativeBridge.getStorageItem(key);
                            try {
                                return JSON.parse(result);
                            } catch(e) {
                                return result;
                            }
                        },
                        
                        removeItem: function(key) {
                            NativeBridge.removeStorageItem(key);
                        },
                        
                        getAllKeys: function() {
                            var result = NativeBridge.getAllStorageKeys();
                            try {
                                return JSON.parse(result);
                            } catch(e) {
                                return [];
                            }
                        },
                        
                        clearStorage: function() {
                            NativeBridge.clearStorage();
                        },
                        
                        requestNotificationPermission: function() {
                            return new Promise(function(resolve) {
                                window.onNotificationPermissionResult = function(granted) {
                                    resolve(granted);
                                    delete window.onNotificationPermissionResult;
                                };
                                NativeBridge.requestNotificationPermission();
                            });
                        },
                        
                        showNotification: function(title, body, id) {
                            NativeBridge.showNotification(title, body, id || Date.now());
                        },
                        
                        getDeviceInfo: function() {
                            var result = NativeBridge.getDeviceInfo();
                            try {
                                return JSON.parse(result);
                            } catch(e) {
                                return {};
                            }
                        },
                        
                        showToast: function(message) {
                            NativeBridge.showToast(message);
                        },

                        vibrate: function(duration) {
                            NativeBridge.vibrate(duration || 200);
                        }
                    };
                    
                    window.NativeBridgeReady = true;
                    var event = new CustomEvent('NativeBridgeReady');
                    document.dispatchEvent(event);
                    
                    console.log('NativeAPI bridge initialized');
                })();
            """.trimIndent()

            view?.evaluateJavascript(jsCode, null)
        }
    }

    inner class AppWebChromeClient : WebChromeClient() {
        override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
            consoleMessage?.let {
                Log.d(TAG, "WebView Console [${it.messageLevel()}]: ${it.message()} (${it.sourceId()}:${it.lineNumber()})")
            }
            return true
        }

        override fun onShowFileChooser(
            webView: WebView?,
            filePathCallback: ValueCallback<Array<Uri>>?,
            fileChooserParams: FileChooserParams?
        ): Boolean {
            fileUploadCallback?.onReceiveValue(null)
            fileUploadCallback = filePathCallback

            val mimeTypes = fileChooserParams?.acceptTypes ?: arrayOf("*/*")
            fileChooserLauncher.launch(mimeTypes)
            return true
        }

        override fun onGeolocationPermissionsShowPrompt(
            origin: String?,
            callback: GeolocationPermissions.Callback?
        ) {
            callback?.invoke(origin, true, false)
        }

        override fun onPermissionRequest(request: PermissionRequest?) {
            request?.grant(request.resources)
        }
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    override fun onResume() {
        super.onResume()
        webView.onResume()
    }

    override fun onPause() {
        super.onPause()
        webView.onPause()
    }

    override fun onDestroy() {
        webView.destroy()
        super.onDestroy()
    }
}

