// NativeBridge.kt - JavaScript Interface
// ============================================================

class NativeBridge(
    private val activity: MainActivity,
    private val webView: WebView
) {
    private val prefs by lazy {
        activity.getSharedPreferences("web_app_storage", Context.MODE_PRIVATE)
    }

    companion object {
        private const val TAG = "NativeBridge"
    }

    // ---- Camera ----

    @JavascriptInterface
    fun openCamera(callbackId: String) {
        Log.d(TAG, "openCamera called with callback: $callbackId")
        activity.runOnUiThread {
            activity.requestCameraPermissionAndLaunch(callbackId)
        }
    }

    @JavascriptInterface
    fun isCameraAvailable(): Boolean {
        return activity.packageManager.hasSystemFeature(PackageManager.FEATURE_CAMERA_ANY)
    }

    // ---- Local Storage ----

    @JavascriptInterface
    fun setStorageItem(key: String, value: String) {
        Log.d(TAG, "setStorageItem: $key")
        prefs.edit().putString(key, value).apply()
    }

    @JavascriptInterface
    fun getStorageItem(key: String): String? {
        Log.d(TAG, "getStorageItem: $key")
        return prefs.getString(key, null)
    }

    @JavascriptInterface
    fun removeStorageItem(key: String) {
        Log.d(TAG, "removeStorageItem: $key")
        prefs.edit().remove(key).apply()
    }

    @JavascriptInterface
    fun getAllStorageKeys(): String {
        val keys = prefs.all.keys
        val jsonArray = org.json.JSONArray(keys.toList())
        return jsonArray.toString()
    }

    @JavascriptInterface
    fun clearStorage() {
        Log.d(TAG, "clearStorage")
        prefs.edit().clear().apply()
    }

    @JavascriptInterface
    fun getStorageSize(): Int {
        return prefs.all.size
    }

    // ---- Push Notifications ----

    @JavascriptInterface
    fun requestNotificationPermission() {
        Log.d(TAG, "requestNotificationPermission")
        activity.runOnUiThread {
            activity.requestNotificationPermission()
        }
    }

    @JavascriptInterface
    fun showNotification(title: String, body: String, notificationId: Int) {
        Log.d(TAG, "showNotification: $title")
        activity.runOnUiThread {
            activity.showNotification(title, body, notificationId)
        }
    }

    @JavascriptInterface
    fun cancelNotification(notificationId: Int) {
        NotificationManagerCompat.from(activity).cancel(notificationId)
    }

    @JavascriptInterface
    fun cancelAllNotifications() {
        NotificationManagerCompat.from(activity).cancelAll()
    }

    // ---- Device Info ----

    @JavascriptInterface
    fun getDeviceInfo(): String {
        val info = JSONObject().apply {
            put("platform", "android")
            put("manufacturer", Build.MANUFACTURER)
            put("model", Build.MODEL)
            put("sdkVersion", Build.VERSION.SDK_INT)
            put("androidVersion", Build.VERSION.RELEASE)
            put("appVersion", try {
                activity.packageManager.getPackageInfo(activity.packageName, 0).versionName
            } catch (e: Exception) {
                "unknown"
            })
            put("packageName", activity.packageName)
            put("screenDensity", activity.resources.displayMetrics.density)
            put("screenWidth", activity.resources.displayMetrics.widthPixels)
            put("screenHeight", activity.resources.displayMetrics.heightPixels)
        }
        return info.toString()
    }

    @JavascriptInterface
    fun getPlatform(): String = "android"

    // ---- Utilities ----

    @JavascriptInterface
    fun showToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun showLongToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_LONG).show()
        }
    }

    @JavascriptInterface
    fun vibrate(durationMs: Long) {
        activity.runOnUiThread {
            val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                val vibratorManager = activity.getSystemService(Context.VIBRATOR_MANAGER_SERVICE)
                        as android.os.VibratorManager
                vibratorManager.defaultVibrator
            } else {
                @Suppress("DEPRECATION")
                activity.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
            }

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                vibrator.vibrate(
                    android.os.VibrationEffect.createOneShot(
                        durationMs,
                        android.os.VibrationEffect.DEFAULT_AMPLITUDE
                    )
                )
            } else {
                @Suppress("DEPRECATION")
                vibrator.vibrate(durationMs)
            }
        }
    }

    @JavascriptInterface
    fun log(message: String) {
        Log.d(TAG, "JS Log: $message")
    }

    @JavascriptInterface
    fun copyToClipboard(text: String) {
        activity.runOnUiThread {
            val clipboard = activity.getSystemService(Context.CLIPBOARD_SERVICE)
                    as android.content.ClipboardManager
            val clip = android.content.ClipData.newPlainText("WebApp", text)
            clipboard.setPrimaryClip(clip)
        }
    }

    @JavascriptInterface
    fun getClipboardText(): String {
        val clipboard = activity.getSystemService(Context.CLIPBOARD_SERVICE)
                as android.content.ClipboardManager
        return clipboard.primaryClip?.getItemAt(0)?.text?.toString() ?: ""
    }

    @JavascriptInterface
    fun shareText(title: String, text: String) {
        activity.runOnUiThread {
            val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                type = "text/plain"
                putExtra(android.content.Intent.EXTRA_TEXT, text)
            }
            activity.startActivity(android.content.Intent.createChooser(intent, title))
        }
    }

    @JavascriptInterface
    fun isNetworkAvailable(): Boolean {
        val connectivityManager = activity.getSystemService(Context.CONNECTIVITY_SERVICE)
                as android.net.ConnectivityManager
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            val network = connectivityManager.activeNetwork
            val capabilities = connectivityManager.getNetworkCapabilities(network)
            capabilities != null && (
                capabilities.hasTransport(android.net.NetworkCapabilities.TRANSPORT_WIFI) ||
                capabilities.hasTransport(android.net.NetworkCapabilities.TRANSPORT_CELLULAR) ||
                capabilities.hasTransport(android.net.NetworkCapabilities.TRANSPORT_ETHERNET)
            )
        } else {
            @Suppress("DEPRECATION")
            connectivityManager.activeNetworkInfo?.isConnected == true
        }
    }
}

